// ── InputBar Component Tests ──

describe("InputBar behavior", () => {
  it("should not call onSend when disabled", () => {
    // Component logic test: InputBar has disabled prop
    // and should not call onSend when disabled=true
    const onSend = vi.fn();
    const disabled = true;
    // Simulate the handleSubmit logic from InputBar.tsx
    const input = "  test  ";
    const trimmed = input.trim();
    if (trimmed && !disabled) {
      onSend(trimmed);
    }
    expect(onSend).not.toHaveBeenCalled();
  });

  it("should trim whitespace before sending", () => {
    const onSend = vi.fn();
    const disabled = false;
    const input = "  hello  ";
    const trimmed = input.trim();
    if (trimmed && !disabled) {
      onSend(trimmed);
    }
    expect(onSend).toHaveBeenCalledWith("hello");
  });

  it("should not send empty messages", () => {
    const onSend = vi.fn();
    const disabled = false;
    const input = "   ";
    const trimmed = input.trim();
    if (trimmed && !disabled) {
      onSend(trimmed);
    }
    expect(onSend).not.toHaveBeenCalled();
  });
});

